Javascript.validate:
			// Validation: Date cannot be in the future. Working day only.	
			
			var interimOrderDate = Services.getValue(InterimOrderDate.dataBinding);
			var err = null;

			if( true == isFutureDate(interimOrderDate))
			{	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
			}
			else if( isNonWorkingDate(interimOrderDate))
		    {   err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg"); 
		    }

		    return err;
